INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-f3743df6-moex-00260', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '證券交易法第66條第2款規定：「證券商違反本法或依本法所發布之命令者，除依本法處罰外， 主管機關並得視情節之輕重，為下列處分，並得命其限期改善：……二、命令該證券商解除其董 事、監察人或經理人職務。……」此處之解除職務，其法律性質為何？', '["其為剝奪或消滅資格、權利之處分，自係行政罰", "其為向未來維持行政秩序所必要之管制性不利處分，並非行政罰", "其為行政執行措施", "其為行政處分之廢止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00261', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於行政罰上的「狀態責任」，下列何者正確？', '["狀態責任係一種結果責任，故其追究即不以構成故意、過失為前提", "行為責任人應同時為狀態責任人，狀態責任係法律之特別規定", "性質上係以對物的狀態具有事實管領力者，得以負責之觀點，課予回復原狀者，其性質即屬狀 態責任", "狀態責任係一種代位責任，故得減輕處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00262', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲公務員不服其服務機關考績丙等之不利處分，於提起行政救濟後，依政府資訊公開法向服務機 關要求調閱考績委員會之會議紀錄，服務機關否准後，於通知A公務員的公文中註記此為行政程 序法第174條之程序行為，應連同考績丙等之不利處分一併救濟。甲服務機關之註記是否正確？', '["不正確，此為對公務員所為之人事行政行為，本無行政程序法程序規定之適用", "不正確，依政府資訊公開法規定申請行政機關提供行政資訊之權利，屬實體權利，行政機關拒 絕提供者，應屬行政處分之性質", "正確，閱覽卷宗請求權屬程序權利，自有行政程序法第174條之適用", "正確，閱覽卷宗請求權屬程序權利，本應有特別之救濟程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00263', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '臺灣地區與大陸地區人民關係條例第95條之3規定，依本條例處理臺灣地區與大陸地區人民往 來有關之事務，不適用行政程序法之規定。有關本條之解釋，下列何者正確？', '["此一規定涉及有關外交行為、軍事行為或國家安全保障事項之行為，自不適用行政程序法", "因為臺灣地區與大陸地區人民關係條例有關程序事項之規定，有較行政程序法更嚴格之程序規 定，故可以排除行政程序法之適用", "此一規定僅排除行政程序法程序規定之適用，行政程序法關於行政行為之實體規定仍有適用", "行政程序法為普通法，其他法律自優先適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00264', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '有關行政程序法規範的迴避，下列何者錯誤？', '["申請迴避之理由僅「釋明」為已足，無庸「證明」", "被申請迴避之公務員在其所屬機關就該申請事件為准許或駁回之決定前，毋庸停止行政程序", "行政程序法並未如同各種訴訟法規定，賦予違反迴避明確之效果", "否准迴避之申請時，得於五日內提請上級機關覆決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00265', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '行政機關之送達證書，僅蓋有大廈管理委員會圖戳代收，並未一併由該管理員以受僱人之身分簽 名或蓋其私章，其送達是否生效？', '["已生效，大廈管理委員會本係應送達處所之有權接收郵件者", "已生效，既有送達證書，即已生送達之效力", "未生效，應送達處所之接收郵件人員應指自然人，送達證書無自然人之簽章自不生效", "未生效，大廈管理委員會及其管理員非應送達處所之有權接收郵件人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00266', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '行政執行法第17條之1規定，義務人為自然人，其滯欠合計達一定金額，已發現之財產不足清 償其所負義務，且生活逾越一般人通常程度者，行政執行處得依職權或利害關係人之申請對其核 發下列各款之禁止命令。有關禁止命令，下列何者錯誤？', '["禁止購買、租賃或使用一定金額以上之商品或服務", "禁止搭乘特定之交通工具", "禁止進入特定之高消費場所消費", "禁止出境、出海"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00267', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲與行政機關締結行政契約，並約定自願接受執行，因未履約而遭行政機關追討違約金，下列何 者正確？', '["此為公法上金錢給付義務之執行，自得移送行政執行分署依行政執行法追討違約金", "行政機關得以該契約為強制執行之執行名義，移送行政執行分署", "行政機關得以該契約為強制執行之執行名義，向行政法院提起給付訴訟", "行政機關得以該契約為強制執行之執行名義，聲請行政法院強制執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00268', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '下列何者係視同訴願決定？', '["依公務人員保障法所為之再申訴決定", "律師懲戒委員會之懲戒決議", "民間之公證人懲戒委員會之懲戒決議", "政府採購申訴審議委員會之審議判斷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00269', 'police-f3743df6', 'police-f3743df6-moex-112-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲公司申請進口管制藥品遭主管機關予以否准，其除提起行政救濟外，甲公司欲提起暫時性權利 保護，應提起下列何者？', '["原否准處分停止執行", "假處分", "假扣押", "假執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "283c6cbbd2a7", "answer_pdf_sha1": "aff2f51980f8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
